/**
 * Evolution Engine — 每日自动分析触发器
 *
 * 在 session_start 中异步触发，每天最多运行一次完整的分析流程。
 * Fire-and-forget：不阻塞 session 初始化。
 *
 * 流程：检查报告 → 获取锁 → 运行 analyzer → summarizer → Judge
 *       → 生成 Markdown 报告 → 合并 pending → 释放锁
 */

import {
	existsSync,
	writeFileSync,
	readFileSync,
	unlinkSync,
	statSync,
	renameSync,
	mkdirSync,
} from "node:fs";
import { homedir } from "node:os";
import { join } from "node:path";
import { execFile } from "node:child_process";

import type { Dirs, JudgeInput, PendingFile, EvolutionSuggestion } from "./types";
import {
	loadPending,
	savePending,
	mergePending,
	saveLastRunStatus,
	loadMetricsHistory,
	loadHistory,
} from "./state";
import { generateDailyReport } from "./report-generator";
import { summarizeReport } from "./summarizer.js";
import { buildEffectReview } from "./effect-tracker.js";
import { runJudge } from "./judge";
import { runGc } from "./gc.js";

// ── 常量 ─────────────────────────────────────────────

/** analyzer 脚本执行超时 */
const ANALYZER_TIMEOUT_MS = 60_000;

const ANALYZER_SCRIPT = join(
	homedir(),
	".pi/agent/scripts/pi-session-analyzer/analyze.py",
);

// ── Lock 管理 ────────────────────────────────────────

interface LockData {
	pid: number;
	timestamp: string;
}

/**
 * 尝试获取锁文件。
 * - 已有锁但 PID 已死 → 清理 stale lock，获取新锁
 * - 已有锁且 PID 存活 → 返回 false
 * - 无锁文件 → 创建并返回 true
 */
function acquireLock(lockPath: string): boolean {
	if (existsSync(lockPath)) {
		try {
			const raw = readFileSync(lockPath, "utf-8");
			const lock = JSON.parse(raw) as LockData;

			// 检查 PID 是否仍然存活
			// process.kill(pid, 0) 不发送信号，只检查进程存在性
			// 注意：此调用假设 Unix 环境（macOS/Linux），Pi 仅在 macOS 上运行
			try {
				process.kill(lock.pid, 0);
				// PID 仍然存活 → 另一个进程在运行
				return false;
			} catch {
				// PID 已死 → stale lock，清理
				unlinkSync(lockPath);
			}
		} catch {
			// 锁文件损坏 → 清理
			unlinkSync(lockPath);
		}
	}

	// 创建新锁
	const data: LockData = { pid: process.pid, timestamp: new Date().toISOString() };
	writeFileSync(lockPath, JSON.stringify(data, null, 2), "utf-8");
	return true;
}

/** 释放锁文件 */
function releaseLock(lockPath: string): void {
	try {
		unlinkSync(lockPath);
	} catch {
		// 锁文件可能已被其他进程清理
	}
}

// ── Pipeline ─────────────────────────────────────────

/**
 * 运行 Python analyzer 生成报告。
 * 返回报告文件路径，失败时抛出错误。
 */
function runAnalyzer(outputPath: string): Promise<string> {
	return new Promise<string>((resolve, reject) => {
		if (!existsSync(ANALYZER_SCRIPT)) {
			reject(new Error(`Session analyzer not found at ${ANALYZER_SCRIPT}`));
			return;
		}

		execFile(
			"python3",
			[ANALYZER_SCRIPT, "--since", "1d", "--format", "json", "--output", outputPath],
			{ timeout: ANALYZER_TIMEOUT_MS },
			(err: Error | null) => {
				if (err) {
					reject(err);
				} else {
					resolve(outputPath);
				}
			},
		);
	});
}

// ── 公共 API ─────────────────────────────────────────

/**
 * 每日自动分析入口。
 * 在 session_start 中调用，fire-and-forget。
 * 同一天只运行一次（通过文件存在性判断）。
 */
export async function checkAndRunDailyAnalysis(dirs: Dirs): Promise<void> {
	const today = new Date().toISOString().slice(0, 10);
	const reportPath = join(dirs.dailyReportsDir, `${today}.md`);

	// AC-2: 同一天不重复生成
	if (existsSync(reportPath) && statSync(reportPath).size > 0) {
		return;
	}

	// 获取锁
	const lockPath = join(dirs.dailyReportsDir, ".daily-report.lock");
	if (!acquireLock(lockPath)) {
		return;
	}

	try {
		// 确保 tmp 目录存在
		if (!existsSync(dirs.tmpDir)) {
			mkdirSync(dirs.tmpDir, { recursive: true });
		}

		// 1. 运行 analyzer
		const tmpReportPath = join(dirs.tmpDir, `daily-raw-${today}.json`);
		await runAnalyzer(tmpReportPath);

		// 2. 读取原始报告
		const rawReport = readFileSync(tmpReportPath, "utf-8");
		const report = JSON.parse(rawReport) as Record<string, unknown>;

		// 3. Summarizer pipeline
		const metricsHistory = loadMetricsHistory(dirs.evolutionDir);
		const signalReport = summarizeReport(
			report,
			metricsHistory,
			dirs.evolutionDir,
			tmpReportPath,
		);

		// 更新内存中的 metrics 历史
		metricsHistory.push(signalReport.metricsSnapshot);

		// 3b. Effect review
		const recentHistory = loadHistory(dirs.evolutionDir, 30);
		const effectReview = buildEffectReview(recentHistory, metricsHistory);
		if (effectReview.length > 0) {
			signalReport.effectReview = effectReview;
		}

		// 3c. GC
		runGc(dirs.evolutionDir);

		// 4. 运行 LLM Judge
		const signalPath = join(
			dirs.signalsDir,
			`signal-${signalReport.metricsSnapshot.date}.json`,
		);
		const judgeInput: JudgeInput = {
			target: "all",
			reportPath: signalPath,
			promptFilePath: "",
		};

		let suggestions: EvolutionSuggestion[];
		try {
			suggestions = await runJudge(judgeInput, dirs.templateDir);
		} catch (err) {
			const msg = err instanceof Error ? err.message : String(err);
			throw new Error(`LLM Judge failed: ${msg}`);
		}

		// 5. 生成 Markdown 报告
		const markdown = generateDailyReport(signalReport, suggestions, effectReview);

		// 6. 原子写入报告文件
		const tmpReport = `${reportPath}.tmp`;
		writeFileSync(tmpReport, markdown, "utf-8");
		renameSync(tmpReport, reportPath);

		// 7. 合并建议到 pending.json
		mergePending(dirs.evolutionDir, suggestions);

		// 8. 记录成功状态
		saveLastRunStatus(dirs.dailyReportsDir, "success");
	} catch (err) {
		// AC-8: 失败不阻塞
		const msg = err instanceof Error ? err.message : String(err);
		console.error(`[evolve] Daily analysis failed: ${msg}`);
		saveLastRunStatus(dirs.dailyReportsDir, "failed", msg);
	} finally {
		releaseLock(lockPath);
	}
}

/**
 * Evolution Engine — 每日报告生成器
 *
 * 将 SignalReport + Suggestions + EffectReview 转换为人类可读的 Markdown 报告。
 */

import type { SignalReport, EvolutionSuggestion, EffectReview } from "./types";

// ── 公共 API ─────────────────────────────────────────

/**
 * 生成每日分析报告的 Markdown 文本。
 * 报告结构：数据概览 → 异常信号 → 趋势变化 → 改进建议 → 效果回顾（条件章节）
 */
export function generateDailyReport(
	signalReport: SignalReport,
	suggestions: EvolutionSuggestion[],
	effectReview?: EffectReview[],
): string {
	const date = new Date(signalReport.generatedAt).toISOString().slice(0, 10);
	const snapshot = signalReport.metricsSnapshot;
	const hasData = snapshot.sessionCount > 0;

	const sections: string[] = [
		`# Evolution Daily Report — ${date}`,
		"",
		"## 数据概览",
		...buildOverview(snapshot, hasData),
		"",
		"## 异常信号",
		...buildAnomalies(signalReport.anomalies),
		"",
		"## 趋势变化",
		...buildTrends(signalReport.trends),
		"",
		"## 改进建议",
		...buildSuggestions(suggestions),
	];

	// 效果回顾：仅有数据时追加
	if (effectReview && effectReview.length > 0) {
		sections.push("", "## 效果回顾", ...buildEffectReview(effectReview));
	}

	return sections.join("\n");
}

// ── 内部格式化函数 ───────────────────────────────────

function buildOverview(
	snapshot: { sessionCount: number; totalToolCalls: number; totalInputTokens: number; totalOutputTokens: number; avgTurnsPerSession: number },
	hasData: boolean,
): string[] {
	if (!hasData) {
		return [
			"- Session 数量：无数据",
			"- 工具调用总数：无数据",
			"- Token 消耗：无数据",
			"- 平均每 session 轮次：无数据",
		];
	}

	return [
		`- Session 数量：${snapshot.sessionCount}`,
		`- 工具调用总数：${snapshot.totalToolCalls}`,
		`- Token 消耗：input ${snapshot.totalInputTokens.toLocaleString()} / output ${snapshot.totalOutputTokens.toLocaleString()}`,
		`- 平均每 session 轮次：${snapshot.avgTurnsPerSession.toFixed(1)}`,
	];
}

function buildAnomalies(anomalies: Array<{ severity: string; detail: string }>): string[] {
	if (anomalies.length === 0) {
		return ["无异常"];
	}

	return anomalies.map(a => `- [${a.severity.toUpperCase()}] ${a.detail}`);
}

function buildTrends(trends: Array<{ field: string; previous: number; current: number; changePercent: number }>): string[] {
	if (trends.length === 0) {
		return ["无显著变化"];
	}

	return trends.map(t => {
		const sign = t.changePercent >= 0 ? "+" : "";
		return `- ${t.field}: ${formatNum(t.previous)} → ${formatNum(t.current)} (${sign}${t.changePercent.toFixed(1)}%)`;
	});
}

function buildSuggestions(suggestions: EvolutionSuggestion[]): string[] {
	if (suggestions.length === 0) {
		return ["系统运行良好，无需调整"];
	}

	const lines: string[] = [];
	for (let i = 0; i < suggestions.length; i++) {
		const s = suggestions[i];
		if (i > 0) lines.push("");
		lines.push(`### #${i} [${s.severity.toUpperCase()}] ${s.title}`);
		if (s.description) lines.push(`- 描述：${s.description}`);
		if (s.rationale) lines.push(`- 依据：${s.rationale}`);
		if (s.targetPath) lines.push(`- 修改目标：${s.targetPath}`);
		if (s.instruction) lines.push(`- 修改指令：${s.instruction}`);
	}
	return lines;
}

function buildEffectReview(reviews: EffectReview[]): string[] {
	return reviews.map(r => {
		const sign = r.changePercent >= 0 ? "+" : "";
		return `- ${r.suggestionTitle}: ${r.targetMetric} ${formatNum(r.before)} → ${formatNum(r.after)} (${sign}${r.changePercent.toFixed(1)}%)`;
	});
}

/** 格式化数字：整数直接显示，浮点保留 2 位 */
function formatNum(n: number): string {
	return Number.isInteger(n) ? String(n) : n.toFixed(2);
}

/**
 * Evolution Engine — 状态持久化
 *
 * 管理 suggestions/pending.json 和 history.jsonl。
 * 所有路径基于传入的 evolutionDir 参数，不硬编码。
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync, appendFileSync } from "node:fs";
import { join } from "node:path";
import type { PendingFile, HistoryEntry, MetricsSnapshot, EvolutionSuggestion } from "./types.js";

// ── 内部路径 ─────────────────────────────────────────

function suggestionsPath(dir: string): string {
	return join(dir, "suggestions", "pending.json");
}

function historyPath(dir: string): string {
	return join(dir, "history.jsonl");
}

function metricsHistoryPath(dir: string): string {
	return join(dir, "metrics-history.json");
}

// ── 公共 API ─────────────────────────────────────────

/**
 * 读取 pending.json。
 * 文件不存在或 JSON 损坏时返回 null。
 */
export function loadPending(dir: string): PendingFile | null {
	const filePath = suggestionsPath(dir);
	if (!existsSync(filePath)) return null;

	try {
		const raw = readFileSync(filePath, "utf-8");
		const pending = JSON.parse(raw) as PendingFile;

		// Migration: 旧格式有 diff 字段而无 instruction，自动迁移
		for (const sug of pending.suggestions) {
			if (!sug.instruction && (sug as unknown as Record<string, unknown>).diff) {
				sug.instruction = String((sug as unknown as Record<string, unknown>).diff);
				delete (sug as unknown as Record<string, unknown>).diff;
			}
		}

		return pending;
	} catch {
		return null;
	}
}

/**
 * 写入 pending.json。
 * 目录不存在时递归创建。
 */
export function savePending(dir: string, pending: PendingFile): void {
	const filePath = suggestionsPath(dir);
	const dirName = join(dir, "suggestions");

	if (!existsSync(dirName)) {
		mkdirSync(dirName, { recursive: true });
	}

	writeFileSync(filePath, JSON.stringify(pending, null, 2), "utf-8");
}

/**
 * 追加一条 JSON 行到 history.jsonl。
 * 文件不存在时创建。
 */
export function appendHistory(dir: string, entry: HistoryEntry): void {
	const filePath = historyPath(dir);

	appendFileSync(filePath, JSON.stringify(entry) + "\n", "utf-8");
}

/**
 * 读取 history.jsonl 最后 N 条记录。
 * 文件不存在返回空数组。
 */
// ── Metrics Snapshot 持久化 ─────────────────────────

/** metrics-history.json 的文件结构 */
interface MetricsHistoryFile {
	snapshots: MetricsSnapshot[];
}

const MAX_METRICS_SNAPSHOTS = 30;

/**
 * 读取 metrics 历史。文件不存在或损坏时返回空数组。
 */
export function loadMetricsHistory(dir: string): MetricsSnapshot[] {
	const filePath = metricsHistoryPath(dir);
	if (!existsSync(filePath)) return [];

	try {
		const raw = readFileSync(filePath, "utf-8");
		const data = JSON.parse(raw) as MetricsHistoryFile;
		return Array.isArray(data.snapshots) ? data.snapshots : [];
	} catch {
		return [];
	}
}

/**
 * 追加一条 snapshot，滑动窗口保留最近 30 条。
 */
export function saveMetricsSnapshot(dir: string, snapshot: MetricsSnapshot): void {
	const history = loadMetricsHistory(dir);
	history.push(snapshot);

	// 滑动窗口：超出上限时删除最老的
	if (history.length > MAX_METRICS_SNAPSHOTS) {
		history.splice(0, history.length - MAX_METRICS_SNAPSHOTS);
	}

	const filePath = metricsHistoryPath(dir);
	writeFileSync(
		filePath,
		JSON.stringify({ snapshots: history }, null, 2),
		"utf-8",
	);
}

// ── History JSONL ────────────────────────────────────

// ── Daily Report 状态 ──────────────────────────────

/** pending.json 中 pending 状态建议的最大数量 */
const MAX_PENDING_SUGGESTIONS = 30;

/**
 * 增量合并新建议到 pending.json。
 * - title 精确匹配去重：已有 pending 建议的 title 与新建议相同时跳过
 * - 容量保护：pending 状态的建议不超过 MAX_PENDING_SUGGESTIONS 条
 * - 无现有文件时创建新 PendingFile
 */
export function mergePending(dir: string, newSuggestions: EvolutionSuggestion[]): void {
	if (newSuggestions.length === 0) return;

	const existing = loadPending(dir);
	if (!existing) {
		const pending: PendingFile = {
			generatedAt: new Date().toISOString(),
			reportUsed: "daily-report",
			suggestions: newSuggestions,
		};
		savePending(dir, pending);
		return;
	}

	// title 去重：跳过与已有 pending 建议同名的
	const pendingTitles = new Set(
		existing.suggestions
			.filter(s => s.status === "pending")
			.map(s => s.title),
	);
	const unique = newSuggestions.filter(s => !pendingTitles.has(s.title));

	if (unique.length > 0) {
		existing.suggestions.push(...unique);
	}

	// 容量保护：超出时将最早的 pending 标记为 rejected
	const pendingCount = existing.suggestions.filter(s => s.status === "pending").length;
	if (pendingCount > MAX_PENDING_SUGGESTIONS) {
		const overflow = pendingCount - MAX_PENDING_SUGGESTIONS;
		let evicted = 0;
		for (const sug of existing.suggestions) {
			if (sug.status === "pending" && evicted < overflow) {
				sug.status = "rejected";
				evicted++;
			}
		}
	}

	savePending(dir, existing);
}

/**
 * 写入每日运行状态文件，供诊断。
 * 文件路径: {dailyReportsDir}/.last-run-status
 */
export function saveLastRunStatus(
	dailyReportsDir: string,
	status: "success" | "failed",
	errorSummary?: string,
): void {
	const filePath = join(dailyReportsDir, ".last-run-status");
	const data = {
		status,
		timestamp: new Date().toISOString(),
		...(errorSummary ? { errorSummary } : {}),
	};
	writeFileSync(filePath, JSON.stringify(data, null, 2), "utf-8");
}

// ── History JSONL ────────────────────────────────────

export function loadHistory(dir: string, limit: number = 10): HistoryEntry[] {
	const filePath = historyPath(dir);
	if (!existsSync(filePath)) return [];

	try {
		const raw = readFileSync(filePath, "utf-8").trim();
		if (raw.length === 0) return [];

		const lines = raw.split("\n");
		const tail = lines.slice(-limit);

		const entries: HistoryEntry[] = [];
		for (const line of tail) {
			const trimmed = line.trim();
			if (trimmed.length === 0) continue;
			try {
				const entry = JSON.parse(trimmed) as HistoryEntry;
				// Migration: 旧格式有 diff 字段而无 instruction
				if (!entry.instruction && (entry as unknown as Record<string, unknown>).diff) {
					entry.instruction = String((entry as unknown as Record<string, unknown>).diff);
					delete (entry as unknown as Record<string, unknown>).diff;
				}
				entries.push(entry);
			} catch {
				// 损坏行跳过
			}
		}
		return entries;
	} catch {
		return [];
	}
}

			return successResult(
				`Rolled back: ${entry.title}`,
				{
					action: "rollback",
					suggestionId: entry.suggestionId,
					targetPath: entry.targetPath,
				},
			);
		}

		throw new Error(`Rollback failed: ${result.reason ?? "unknown"}`);
	} catch (err) {
		const msg = err instanceof Error ? err.message : String(err);
		throw new Error(`Unexpected error in /evolve-rollback: ${msg}`);
	}
}

// ── handleEvolveReport ───────────────────────────────

/**
 * /evolve-report handler:
 * - 无参数 → 显示今天的报告
 * - YYYY-MM-DD → 显示指定日期的报告
 * - --list → 列出所有可用报告（最近 10 条）
 */
export function handleEvolveReport(args: string, dirs: Dirs): CommandResult {
	try {
		const trimmed = args.trim();
		const today = new Date().toISOString().slice(0, 10);

		// ── --list: 列出所有报告 ─────────────────────
		if (trimmed === "--list") {
			return listReports(dirs, today);
		}

		// ── 指定日期或今天 ────────────────────────────
		const targetDate = isDateString(trimmed) ? trimmed : today;
		const reportPath = join(dirs.dailyReportsDir, `${targetDate}.md`);

		if (!existsSync(reportPath)) {
			// 如果是今天的报告缺失，提供额外诊断信息
			if (targetDate === today) {
				const statusInfo = readLastRunStatus(dirs.dailyReportsDir);
				const statusLine = statusInfo
					? `\n最后运行状态: ${statusInfo.status} (${statusInfo.timestamp})${statusInfo.errorSummary ? `\n错误: ${statusInfo.errorSummary}` : ""}`
					: "";
				throw new Error(`今天的报告尚未生成。${statusLine}`);
			}
			throw new Error(`${targetDate} 的报告不存在`);
		}

		const content = readFileSync(reportPath, "utf-8");
		return successResult(content, {
			action: "report",
			date: targetDate,
			size: content.length,
		});
	} catch (err) {
		const msg = err instanceof Error ? err.message : String(err);
		throw new Error(`Unexpected error in /evolve-report: ${msg}`);
	}
}

// ── Report 辅助函数 ─────────────────────────────────

/** 列出所有可用报告 */
function listReports(dirs: Dirs, today: string): CommandResult {
	if (!existsSync(dirs.dailyReportsDir)) {
		return successResult("尚未生成任何报告。", { action: "list", reports: [] });
	}

	const entries = readdirSync(dirs.dailyReportsDir)
		.filter(name => name.endsWith(".md") && !name.startsWith("."))
		.sort()
		.reverse()
		.slice(0, 10);

	if (entries.length === 0) {
		return successResult("尚未生成任何报告。", { action: "list", reports: [] });
	}

	// 读取最后运行状态
	const statusInfo = readLastRunStatus(dirs.dailyReportsDir);
	const todayReport = `${today}.md`;
	const todayExists = entries.some(e => e === todayReport);

	// 检查最近 7 天缺失日期
	const missingDates: string[] = [];
	for (let i = 0; i < 7; i++) {
		const d = new Date(Date.now() - i * MS_PER_DAY).toISOString().slice(0, 10);
		if (!entries.some(e => e === `${d}.md`)) {
			missingDates.push(d);
		}
	}

	const lines: string[] = ["可用报告:"];
	for (const name of entries) {
		const date = name.replace(".md", "");
		const marker = date === today ? " ← 今天" : "";
		lines.push(`  ${date}${marker}`);
	}

	if (statusInfo) {
		lines.push(`\n最后运行: ${statusInfo.status} (${statusInfo.timestamp})`);
	}

	if (!todayExists) {
		lines.push("\n⚠ 今天的报告尚未生成");
	}

	if (missingDates.length > 0) {
		lines.push(`\n最近 7 天缺失: ${missingDates.join(", ")}`);
	}

	return successResult(lines.join("\n"), {
		action: "list",
		reports: entries.map(e => e.replace(".md", "")),
		todayGenerated: todayExists,
		missingDates,
	});
}

interface LastRunStatus {
	status: string;
	timestamp: string;
	errorSummary?: string;
}

/** 读取 .last-run-status 文件 */
function readLastRunStatus(dailyReportsDir: string): LastRunStatus | null {
	const statusPath = join(dailyReportsDir, ".last-run-status");
	if (!existsSync(statusPath)) return null;

	try {
		const raw = readFileSync(statusPath, "utf-8");
		return JSON.parse(raw) as LastRunStatus;
	} catch {
		return null;
	}
}

/** 检查字符串是否匹配 YYYY-MM-DD 格式 */
function isDateString(s: string): boolean {
	return /^\d{4}-\d{2}-\d{2}$/.test(s) && !Number.isNaN(new Date(s).getTime());
}

/**
 * Evolution Engine — 数据垃圾回收
 *
 * 清理过期的 reports、signals、daily 数据文件，防止磁盘无限膨胀。
 * 由 /evolve 命令在每次运行后自动调用。
 */

import { existsSync, readdirSync, unlinkSync, statSync } from "node:fs";
import { join } from "node:path";

// ── GC 策略常量 ──────────────────────────────────────

/** reports/*.json 保留最新 N 个 */
const MAX_REPORTS = 3;

/** signals/*.json 保留最新 N 个 */
const MAX_SIGNALS = 30;

/** daily/*.json 保留天数 */
const MAX_DAILY_DAYS = 90;

/** daily-reports/*.md 保留天数 */
const MAX_DAILY_REPORT_DAYS = 30;

// ── 辅助函数 ─────────────────────────────────────────

/** 安全地按修改时间降序排列目录中的 .json 文件 */
function listJsonByMtime(dir: string): string[] {
	if (!existsSync(dir)) return [];

	try {
		const entries = readdirSync(dir);
		return entries
			.filter(name => name.endsWith(".json"))
			.map(name => ({
				name,
				path: join(dir, name),
				mtime: statSync(join(dir, name)).mtimeMs,
			}))
			.sort((a, b) => b.mtime - a.mtime)
			.map(e => e.path);
	} catch {
		return [];
	}
}

/** 删除指定文件路径列表 */
function removeFiles(paths: string[]): number {
	let removed = 0;
	for (const p of paths) {
		try {
			unlinkSync(p);
			removed++;
		} catch (err) {
			// 文件可能已被其他进程删除，记录但不停滞
			console.warn(`[evolve-gc] Failed to remove ${p}: ${err instanceof Error ? err.message : String(err)}`);
		}
	}
	return removed;
}

/** 从 daily 文件名提取日期并过滤超过 N 天的 */
function listExpiredDaily(dir: string, maxDays: number): string[] {
	if (!existsSync(dir)) return [];

	const cutoff = Date.now() - maxDays * 24 * 60 * 60 * 1000;

	try {
		const entries = readdirSync(dir);
		const expired: string[] = [];

		for (const name of entries) {
			if (!name.endsWith(".json")) continue;

			// daily 文件名格式: 2026-05-27.json
			const dateStr = name.replace(".json", "");
			const fileTime = new Date(dateStr).getTime();

			// 文件名无法解析为日期时，用 mtime 兜底
			const effectiveTime = Number.isNaN(fileTime)
				? statSync(join(dir, name)).mtimeMs
				: fileTime;

			if (effectiveTime < cutoff) {
				expired.push(join(dir, name));
			}
		}

		return expired;
	} catch {
		return [];
	}
}

/** 从 daily-reports 文件名提取日期并过滤超过 N 天的指定扩展名文件 */
function listExpiredDailyByExt(dir: string, maxDays: number, ext: string): string[] {
	if (!existsSync(dir)) return [];

	const cutoff = Date.now() - maxDays * 24 * 60 * 60 * 1000;

	try {
		const entries = readdirSync(dir);
		const expired: string[] = [];

		for (const name of entries) {
			// 排除 dotfile 和不匹配扩展名的文件
			if (!name.endsWith(ext) || name.startsWith(".")) continue;

			// 文件名格式: 2026-05-27.md
			const dateStr = name.replace(ext, "");
			const fileTime = new Date(dateStr).getTime();

			// 文件名无法解析为日期时，用 mtime 兜底
			const effectiveTime = Number.isNaN(fileTime)
				? statSync(join(dir, name)).mtimeMs
				: fileTime;

			if (effectiveTime < cutoff) {
				expired.push(join(dir, name));
			}
		}

		return expired;
	} catch {
		return [];
	}
}

// ── 公共 API ─────────────────────────────────────────

/** GC 清理结果 */
export interface GcResult {
	reportsRemoved: number;
	signalsRemoved: number;
	dailyRemoved: number;
	dailyReportsRemoved: number;
}

/**
 * 执行数据垃圾回收。
 * 目录不存在时静默跳过，不报错。
 */
export function runGc(evolutionDir: string): GcResult {
	const reportsDir = join(evolutionDir, "reports");
	const signalsDir = join(evolutionDir, "signals");
	const dailyDir = join(evolutionDir, "daily");

	// reports: 保留最新 MAX_REPORTS 个
	const reportFiles = listJsonByMtime(reportsDir);
	const reportsToRemove = reportFiles.slice(MAX_REPORTS);
	const reportsRemoved = removeFiles(reportsToRemove);

	// signals: 保留最新 MAX_SIGNALS 个
	const signalFiles = listJsonByMtime(signalsDir);
	const signalsToRemove = signalFiles.slice(MAX_SIGNALS);
	const signalsRemoved = removeFiles(signalsToRemove);

	// daily: 保留 MAX_DAILY_DAYS 天内
	const expiredDaily = listExpiredDaily(dailyDir, MAX_DAILY_DAYS);
	const dailyRemoved = removeFiles(expiredDaily);

	// daily-reports: 保留 MAX_DAILY_REPORT_DAYS 天内的 .md 文件
	let dailyReportsRemoved = 0;
	const dailyReportsDir = join(evolutionDir, "daily-reports");
	if (existsSync(dailyReportsDir)) {
		const expiredReports = listExpiredDailyByExt(dailyReportsDir, MAX_DAILY_REPORT_DAYS, ".md");
		dailyReportsRemoved = removeFiles(expiredReports);
	}

	return { reportsRemoved, signalsRemoved, dailyRemoved, dailyReportsRemoved };
}

